INSERT INTO locations (name, description, video_url) VALUES
  ('Pallet Town',    'A small, quiet town in the southwest corner of Kanto. It is home to the player, their rival, and Professor Oak''s Pokemon research laboratory where new trainers receive their first Pokemon.', NULL),
  ('Viridian City',  'A small city surrounded by lush green forests. It houses the final gym in the Kanto region, led by the mysterious Giovanni, as well as a Pokemon Center and Poke Mart.', NULL),
  ('Pewter City',    'A quiet city nestled between rocky mountains and dense forest. It is home to the first Kanto gym, led by the rock-type specialist Brock, and the Pewter Museum of Science.', NULL),
